    /// Lists all payments for a given user, ordered by creation date descending.
    /// </summary>
    Task<IReadOnlyList<Payment>> GetPaymentsByUserAsync(Guid userId, int skip = 0, int take = 20, CancellationToken cancellationToken = default);
}

