    25→        {
    26→            errors.Add("Amount must be greater than zero.");
    27→        }
    28→
    29→        if (command.Amount > 1_000_000m)
    30→        {
    31→            errors.Add("Amount exceeds maximum allowed value of 1,000,000.");
    32→        }
